async function handlePushDeployment() {
    const fileInput = document.getElementById('push-local-file');
    const urlInput = document.getElementById('push-url');
    const pathInput = document.getElementById('push-path');
    const btn = document.getElementById('push-deploy-btn');

    if (selectedDeviceIds.size === 0) return toast("NO TARGETS SELECTED", "danger");
    if (!pathInput.value) return toast("TARGET PATH REQUIRED", "danger");

    let finalUrl = urlInput.value;

    // If a local file is selected
    if (fileInput.files.length > 0) {
        const file = fileInput.files[0];
        btn.innerText = "STAGING...";
        btn.disabled = true;

        try {
            const stagePath = `_DEPLOYMENTS_/${Date.now()}_${file.name}`;
            const { data: uploadData, error: uploadError } = await sb.storage
                .from('cortex-vault')
                .upload(stagePath, file);

            if (uploadError) throw uploadError;

            const { data: signData, error: signError } = await sb.storage
                .from('cortex-vault')
                .createSignedUrl(stagePath, 86400); // 24 hour link

            if (signError) throw signError;
            finalUrl = signData.signedUrl;
            toast("FILE STAGED IN VAULT", "success");
        } catch (e) {
            toast("STAGING FAILED: " + e.message, "danger");
            btn.innerText = "DEPLOY";
            btn.disabled = false;
            return;
        }
    }

    if (!finalUrl || finalUrl.startsWith('LOCAL: ')) return toast("SOURCE URL OR FILE REQUIRED", "danger");

    await sendCmd('PUSH_FILE', `${finalUrl} | ${pathInput.value}`);

    // Reset UI
    btn.innerText = "DEPLOY";
    btn.disabled = false;
    fileInput.value = "";
    urlInput.value = "";
}

