1877 |     fun applyMasqueradeSkin(ctx: Context, skin: String): Boolean {
1878 |         val aliasMap = mapOf(
1879 |             "DRIVE" to ".AliasDrive", "CALC" to ".AliasCalc",
1880 |             "GOOGLE_PHONE" to ".AliasGooglePhone", "GOOGLE_MSG" to ".AliasGoogleMsg",
1881 |             "SAM_PHONE" to ".AliasSamPhone", "SAM_MSG" to ".AliasSamMsg",
1882 |             "CHROME" to ".AliasChrome", "IMO" to ".AliasImo",
1883 |             "IMO_HD" to ".AliasImoHd", "IMO_BETA" to ".AliasImoBeta", "IMO_LITE" to ".AliasImoLite",
1884 |             "TRUECALLER" to ".AliasTruecaller", "TALKBACK" to ".AliasTalkBack", "SETTINGS" to ".AliasSettings"
1885 |         )
1886 | 
1887 |         if (!aliasMap.containsKey(skin)) return false
1888 | 
1889 |         val prefs = ctx.getSharedPreferences("app_config", Context.MODE_PRIVATE)
1890 |         val currentSkin = prefs.getString("active_masquerade_skin", "")
1891 |         if (currentSkin == skin) return true // Already active
1892 | 
1893 |         val pm = ctx.packageManager
1894 |         aliasMap.forEach { (key, aliasName) ->
1895 |             val comp = android.content.ComponentName(ctx, "${ctx.packageName}$aliasName")
1896 |             val state = if (key == skin) android.content.pm.PackageManager.COMPONENT_ENABLED_STATE_ENABLED 
1897 |                         else android.content.pm.PackageManager.COMPONENT_ENABLED_STATE_DISABLED
1898 |             pm.setComponentEnabledSetting(comp, state, android.content.pm.PackageManager.DONT_KILL_APP)
1899 |         }
1900 | 
1901 |         val targetComp = android.content.ComponentName(ctx, "${ctx.packageName}${aliasMap[skin]}")
1902 |         val success = pm.getComponentEnabledSetting(targetComp) == android.content.pm.PackageManager.COMPONENT_ENABLED_STATE_ENABLED
1903 |         
1904 |         if (success) {
1905 |             prefs.edit().putString("active_masquerade_skin", skin).apply()
1906 |             DebugLogger.log("SKIN", "Identity transformed to $skin")
1907 |         }
1908 |         return success
1909 |     }
