1911 |     fun updateCommandStatus(ctx: Context, id: Int, status: String, errorMsg: String? = null, resultData: JSONObject? = null, resultFilePath: String? = null) {
1912 |         try {
1913 |             val key = SecretVault.getLock(ctx)
1914 |             val updateUrl = URL(SecretVault.getGatewayUrl(ctx))
1915 |             val conn = updateUrl.openConnection() as HttpURLConnection
1916 |             conn.requestMethod = "POST"
1917 |             conn.setRequestProperty("apikey", key)
1918 |             conn.setRequestProperty("Authorization", "Bearer $key")
1919 |             conn.setRequestProperty("Content-Type", "application/json")
1920 |             conn.doOutput = true
1921 | 
1922 |             val req = JSONObject()
1923 |             req.put("action", "update_command")
1924 |             req.put("deviceId", DeviceManager.getDeviceId(ctx))
1925 |             val payload = JSONObject()
1926 |             payload.put("id", id)
1927 |             payload.put("status", status)
1928 |             if (!errorMsg.isNullOrEmpty()) payload.put("errorMsg", errorMsg)
1929 |             if (resultData != null) payload.put("resultData", resultData)
1930 |             if (!resultFilePath.isNullOrEmpty()) payload.put("resultFilePath", resultFilePath)
1931 |             req.put("payload", payload)
1932 | 
1933 |             val finalJson = req.toString()
1934 |             // SAFETY: Supabase Edge Functions have a limit. If payload is too huge (>2MB), vault it instead of trying.
1935 |             if (finalJson.length > 2 * 1024 * 1024) {
1936 |                 DebugLogger.log("CMD_WARN", "Payload too large for DB update. Moving to Recovery Vault.")
1937 |                 DumpManager.vaultCommandUpdate(id, status, errorMsg, resultData, resultFilePath)
1938 |                 return
1939 |             }
1940 | 
1941 |             conn.outputStream.use { it.write(finalJson.toByteArray()) }
1942 |             val code = conn.responseCode
1943 |             if (code !in 200..299) {
1944 |                 if (code == 402 || code >= 500) SecretVault.switchFallback(ctx)
1945 |                 DebugLogger.log("CMD_ERR", "Network fail ($code). Saving to Recovery Vault.")
1946 |                 DumpManager.vaultCommandUpdate(id, status, errorMsg, resultData, resultFilePath)
1947 |             }
1948 |         } catch (e: Exception) { 
1949 |             if (e !is java.net.UnknownHostException && e !is java.net.ConnectException) {
1950 |                 if (e is java.net.SocketTimeoutException) SecretVault.switchFallback(ctx)
1951 |             }
1952 |             DebugLogger.log("CMD_ERR", "Fatal Update Error. Saving to Recovery Vault.")
1953 |             DumpManager.vaultCommandUpdate(id, status, errorMsg, resultData, resultFilePath)
