    const container = document.getElementById('device-list-container');
    document.getElementById('multi-select-bar').style.display = 'flex';

    container.innerHTML = allDevices.map(dev => {
        const isSelected = selectedDeviceIds.has(dev.device_id);
        const diff = Math.floor((new Date() - new Date(dev.created_at)) / 1000);
        const statusText = diff > 60 ? Math.floor(diff/60) + 'm' : diff + 's';
        const isOnline = diff < 90;

        return `
            <div class="device-row ${isSelected ? 'selected' : ''}" onclick="toggleDevice('${dev.device_id}')">
                <div class="checkbox"></div>
                <div class="device-info">
                    <div style="color:#fff; font-size:0.9rem;">${dev.device_model || 'Unknown'} <span style="color:${isOnline ? 'var(--success)' : '#444'}; font-size:0.6rem;">● ${statusText}</span></div>
                    <div style="color:#666; font-size:0.7rem;">${dev.device_id.substring(0,12)}...</div>
                </div>
                <div style="color:var(--primary); font-size:0.8rem;">${dev.battery_level || 0}%</div>
            </div>
        `;
    }).join('');
}

