async function getFriendlyBlob(fullPath, originalName) {
    const { data, error } = await sb.storage.from('cortex-vault').createSignedUrl(fullPath, 60);
    if (error) throw error;

    const resp = await fetch(data.signedUrl);
    let buffer = await resp.arrayBuffer();
    let fileName = originalName;

    // 1. Decompress if GZIP
    if (fileName.toLowerCase().endsWith('.gz')) {
        buffer = await decompressGzip(buffer);
        fileName = fileName.slice(0, -3);
    }

    // 2. Decrypt if CTX
    if (fileName.toLowerCase().endsWith('.ctx')) {
        buffer = await decryptCtx(buffer);
        fileName = fileName.slice(0, -4) + ".json";
    }

    return { blob: new Blob([buffer]), name: fileName };
}

